# Configuration
WINDOW_SIZE = 1000
K = 6

def kmer_tokenizer(sequence, k=K):
    return " ".join([sequence[i:i+k] for i in range(len(sequence) - k + 1)])

def get_sequences_and_labels(chrom_name, fasta_file, peaks_df):
    print(f"Extracting data from {chrom_name}...")
    genome_chrom = Fasta(fasta_file)

    # Filter peaks for the specific chromosome
    peaks_chrom = peaks_df[peaks_df[0] == chrom_name]

    sequences = []
    labels = []

    # Positives (Class 1)
    for _, row in peaks_chrom.iterrows():
        center = (row[1] + row[2]) // 2
        start, end = center - (WINDOW_SIZE // 2), center + (WINDOW_SIZE // 2)

        if start > 0 and end < len(genome_chrom[chrom_name]):
            seq = genome_chrom[chrom_name][start:end].seq.upper()
            # Ensure no undefined bases ('N') and correct length
            if 'N' not in seq and len(seq) == WINDOW_SIZE:
                sequences.append(kmer_tokenizer(seq))
                labels.append(1)

    # Negatives (Class 0)
    pos_count = len(sequences)
    neg_count = 0
    chrom_len = len(genome_chrom[chrom_name])

    while neg_count < pos_count:
        rand_start = random.randint(0, chrom_len - WINDOW_SIZE)
        rand_end = rand_start + WINDOW_SIZE
        seq = genome_chrom[chrom_name][rand_start:rand_end].seq.upper()

        if 'N' not in seq and len(seq) == WINDOW_SIZE:
            sequences.append(kmer_tokenizer(seq))
            labels.append(0)
            neg_count += 1

    return sequences, labels


peaks_all = pd.read_csv('ENCFF246KRE.bed.gz', sep='\t', header=None)

# Train (Chromosome 8)
X_train, Y_train = get_sequences_and_labels('chr8', 'chr8.fa', peaks_all)

