"""# GenomicDataSet"""

import torch
from torch.utils.data import Dataset, DataLoader
from transformers import BertTokenizer

class GenomicDataset(Dataset):
    def __init__(self, sequences, labels, tokenizer, max_length=512):
        self.sequences = sequences
        self.labels = labels
        self.tokenizer = tokenizer
        self.max_length = max_length

    def __len__(self):
        return len(self.sequences)

    def __getitem__(self, idx):

        inputs = self.tokenizer(
            self.sequences[idx],
            add_special_tokens=True,
            max_length=self.max_length,
            padding='max_length',
            truncation=True,
            return_tensors='pt'
        )

        return {
            'input_ids': inputs['input_ids'].flatten(),
            'attention_mask': inputs['attention_mask'].flatten(),
            'labels': torch.tensor(self.labels[idx], dtype=torch.long)
        }
from transformers import BertTokenizer

tokenizer = BertTokenizer.from_pretrained("zhihan1996/DNA_bert_6")

train_dataset = GenomicDataset(X_train, Y_train, tokenizer, max_length=512)
val_dataset = GenomicDataset(X_val, Y_val, tokenizer, max_length=512)
test_dataset = GenomicDataset(X_test, Y_test, tokenizer, max_length=512)

train_loader = DataLoader(train_dataset, batch_size=32, shuffle=True)
val_loader = DataLoader(val_dataset, batch_size=32, shuffle=False)
test_loader = DataLoader(test_dataset, batch_size=32, shuffle=False)

