from transformers import BertForSequenceClassification
import torch

device = torch.device("cuda" if torch.cuda.is_available() else "cpu")
print(f"using device: {device}")

model = BertForSequenceClassification.from_pretrained("zhihan1996/DNA_bert_6", num_labels=2)
model.to(device)

"""## Training"""

from torch.optim import AdamW

optimizer = AdamW(model.parameters(), lr=5e-5)

model.train()
epochs = 3

for epoch in range(epochs):
    total_loss = 0
    for batch in train_loader:

        input_ids = batch['input_ids'].to(device)
        attention_mask = batch['attention_mask'].to(device)
        labels = batch['labels'].to(device)


        model.zero_grad()


        outputs = model(input_ids, attention_mask=attention_mask, labels=labels)
        loss = outputs.loss


        loss.backward()
        optimizer.step()

        total_loss += loss.item()

    avg_loss = total_loss / len(train_loader)
    print(f"Epoch {epoch+1} finalized. Loss average: {avg_loss:.4f}")

"""# Evaluation and Metrics"""

model.eval()

y_true = []
y_pred = []

print("Calculating predictions on chromosome 10...")

with torch.no_grad():
    for batch in test_loader:
        input_ids = batch['input_ids'].to(device)
        attention_mask = batch['attention_mask'].to(device)
        labels = batch['labels'].to(device)

        # Get model output
        outputs = model(input_ids, attention_mask=attention_mask)

        # The model returns 'logits'.  argmax to get the class (0 or 1)
        predictions = torch.argmax(outputs.logits, dim=1)

        # Saving
        y_true.extend(labels.cpu().numpy())
        y_pred.extend(predictions.cpu().numpy())

