# settings for DNABERT-6
window_size = 512
half_window = window_size // 2

def get_prediction(sequence, model, tokenizer):
    """
    Transforms a sequence into k-mers and returns the probability
    of the 'Open Chromatin' class.
    """
    # Create 6-mers
    kmers = " ".join([sequence[j:j+6] for j in range(len(sequence)-5)])

    # Tokenize
    inputs = tokenizer(kmers, return_tensors="pt", padding='max_length',
                       max_length=512, truncation=True).to(device)

    # Inference
    with torch.no_grad():
        outputs = model(**inputs)
        # Apply Softmax to get probabilities [Closed (0), Open (1)]
        probs = torch.nn.functional.softmax(outputs.logits, dim=-1)
        return probs[0][1].item()

